const https = require('https');
const http = require('http');
const { JSDOM } = require('jsdom');

exports.fetchUrlMetadata = async (req, res) => {
  try {
    const url = req.body.url;
    if (!url) {
      return res.status(400).send('URL is required');
    }

    const fetchPage = (url) => {
      return new Promise((resolve, reject) => {
        const client = url.startsWith('https') ? https : http;
        client.get(url, (response) => {
          if (response.statusCode !== 200) {
            reject(new Error('Failed to load page, status code: ' + response.statusCode));
          }
          let data = '';
          response.on('data', (chunk) => (data += chunk));
          response.on('end', () => resolve(data));
        }).on('error', (err) => reject(err));
      });
    };

    const html = await fetchPage(url);
    const dom = new JSDOM(html);
    const document = dom.window.document;

    const getMetaTagContent = (property) => {
      const element = document.querySelector(`meta[property='${property}']`) || document.querySelector(`meta[name='${property}']`);
      return element ? element.getAttribute('content') : null;
    };

    const metadata = {
      title: document.querySelector('title') ? document.querySelector('title').textContent : null,
      description: getMetaTagContent('description'),
      ogTitle: getMetaTagContent('og:title'),
      ogDescription: getMetaTagContent('og:description'),
      ogImage: getMetaTagContent('og:image'),
      ogUrl: getMetaTagContent('og:url'),
    };

    res.status(200).json(metadata);
  } catch (error) {
    res.status(500).send('Error fetching metadata: ' + error.message);
  }
};